function getAccountDetails(selectedAccountNumber) {
    const accountList = Context.getVariable("account_list").accounts;

    const last4 = String(selectedAccountNumber).slice(-4);

    const account = accountList.find(acc => acc.account_number.endsWith(last4));
    if (!account) return null;

    Context.setVariable("account_id", account.id)
    Context.setVariable("account_number", account.account_number)
    Context.setVariable("account_type", account.account_type)
    Context.setVariable("account_balance", account.balance)
    Context.setVariable("account_available_balance", account.available_balance)

    const account_type_set1 = ['DEBIT', 'SAVINGS', 'CHECKING', 'CERTIFICATE_OF_DEPOSIT', 'STUDENT', 'OTHER', 'UNDEFINED'];
    const account_type_set2 = ['CREDIT_CARD', 'CREDIT', 'BUSINESS_CREDIT_CARD', 'STUDENT_CREDIT_CARD', 'PERSONAL_CREDIT_CARD'];
    const account_type_set3 = ['MORTGAGE_LOAN', 'HOME_EQUITY_LOAN', 'AUTO_LOAN', 'PERSONAL_LOAN', 'BUSINESS_LOAN', 'STUDENT_LOAN'];

    const account_type = account.account_type;
    let account_type_option = -1;
    let account_balance_information = "";
    if (account_type_set1.indexOf(account_type) > -1) {
        account_type_option = 1
        if (account.balance !== account.available_balance) {
            account_balance_information = "Your current balance is " + account.balance + " dollars and your available balance is " + account.available_balance + " dollars."
        } else {
            account_balance_information = "Your current and available balance is " + account.balance + " dollars."
        }
    }
    else if (account_type_set2.indexOf(account_type) > -1) {
        account_type_option = 2
        // Context.setVariable("account_credit_limit", account.credit_limit)
        if (account.balance !== account.available_balance) {
            account_balance_information = "Your current balance is " + account.balance + " dollars and your available balance is " + account.available_balance + " dollars. Your total credit limit is " + account.credit_limit + " dollars."
        } else {
            account_balance_information = "Your current and available balance is " + account.balance + " dollars. Your total credit limit is " + account.credit_limit + " dollars."
        }
    }
    else if (account_type_set3.indexOf(account_type) > -1) {
        account_type_option = 3
        account_balance_information = "Your current principal balance is " + account.balance + " dollars. Would you like to know more information about your loan?"
    }

    Context.setVariable('account_type_option', account_type_option)
    Context.setVariable('account_balance_information', account_balance_information)

}

