const contact_address_list = Context.getVariable("contact_address");

if (contact_address_list && contact_address_list.length != 0) {
	const contactAddress = contact_address_list[0];

	let address = '';

	const separator = ',';

	if (contactAddress.street) {
		address += `${contactAddress.street}`;
	}

	if (contactAddress.city) {
		address += `${separator} ${contactAddress.city}`;
	}

	if (contactAddress.state || contactAddress.postal_code || contactAddress.district) {
		address += `${separator}`;
		if (contactAddress.state) {
			address += ` ${contactAddress.state}`;
		}
		if (contactAddress.postal_code) {
			Context.setVariable("card_postal_code", contactAddress.postal_code);
            Context.setVariable("postal_code_found", true);
		}else {
			Context.setVariable("postal_code_found", false);
		}
		if (contactAddress.district) {
			address += ` ${contactAddress.district}`;
		}
	}

	if (contactAddress.country) {
		address += `${separator} ${contactAddress.country}`;
	}

	if (address.startsWith(separator)) {
		address = address.substring(separator.length);
	}

	Context.setVariable("card_shipping_address", address);
    Context.setVariable("shipping_address_found", true);
}else{
	Context.setVariable("shipping_address_found", false);
}

